import {
  ChangeDetectionStrategy,
  Component,
  ViewEncapsulation,
  input,
  output,
} from '@angular/core';

/** A smart component demonstrating signal-based input and output APIs. */
@Component({
  selector: 'smart-ngx-smart-components',
  imports: [],
  template: `<p>{{ sampleInput() }}</p>`,
  styles: `
    :host {
      display: block;
    }
  `,
  encapsulation: ViewEncapsulation.Emulated,
  changeDetection: ChangeDetectionStrategy.OnPush,
})
export class NgxSmartComponents {
  /** The label displayed in the component. */
  readonly sampleInput = input<string>('');

  /** Emitted when the component action occurs. */
  readonly sampleOutput = output<void>();
}

